+            *value = "not-a-url".into();
+        }
+        if let Some(FormField::Select { selected, .. }) = self.form.field_mut(7) {
+            *selected = 0;
+        }
+        if let Some(FormField::Checkbox { checked, .. }) = self.form.field_mut(8) {
